'use client';

import { useState } from 'react';

export function UnitCalculator() {
    const [quantity, setQuantity] = useState<number>(1);
    const [fromUnit, setFromUnit] = useState('Box'); // Hardcoded for demo, ideally dynamic
    const [result, setResult] = useState<string>('12 Pieces'); // Placeholder logic

    const handleCalculate = () => {
        // In a real app, we'd need access to unit definitions here
        // For now, this is just making the UI interactive as requested
        setResult(`${quantity * 12} Pieces (Approx)`);
    };

    return (
        <div className="card-premium p-6 bg-blue-50/30 border-blue-100">
            <h3 className="font-bold text-gray-900 mb-4">Unit Conversion Calculator</h3>
            <div className="flex items-end gap-4">
                <div className="flex-1">
                    <label className="block text-xs font-semibold text-gray-500 mb-1 uppercase tracking-wider">Quantity</label>
                    <input
                        type="number"
                        value={quantity}
                        onChange={(e) => setQuantity(Number(e.target.value))}
                        className="input-field bg-white"
                        placeholder="1"
                    />
                </div>
                <div className="flex-1">
                    <label className="block text-xs font-semibold text-gray-500 mb-1 uppercase tracking-wider">From Unit</label>
                    <select
                        className="input-field bg-white"
                        value={fromUnit}
                        onChange={(e) => setFromUnit(e.target.value)}
                    >
                        <option>Piece</option>
                        <option>Pack</option>
                        <option>Box</option>
                    </select>
                </div>
                <div className="pb-3 text-gray-400 font-bold">=</div>
                <div className="flex-1">
                    <label className="block text-xs font-semibold text-gray-500 mb-1 uppercase tracking-wider">To Base Unit</label>
                    <input type="text" className="input-field bg-gray-100" value={result} readOnly disabled />
                </div>
            </div>
            <p className="text-xs text-gray-400 mt-2 italic">* This calculator is currently a demonstration and uses fixed values.</p>
        </div>
    );
}
